#!/usr/bin/env ocaml
(* minigit implementation in OCaml *)

let init () =
  if Sys.file_exists ".minigit" then
    (prerr_endline "minigit: .minigit already exists"; exit 1)
  else
    (Unix.mkdir ".minigit" 0o755;
     Unix.mkdir ".minigit/objects" 0o755;
     let oc = open_out ".minigit/index" in
     close_out oc)

let hash_contents contents =
  let open Digest in
  let len = String.length contents in
  let pack = String.make 4 '\000' in
  for i = 0 to 3 do
    pack.[i] <- char_of_int ((len lsl (8 * (3 - i))) land 0xFF)
  done;
  let header = String.make 1 '\x00' in
  header.[0] <- char_of_int (String.length contents);
  let data = header ^ contents in
  let checksum = String.sub (string data) 0 2 in
  let hex = String.make 4 '\000' in
  for i = 0 to 1 do
    let c = int_of_char checksum.[i] in
    hex.[2*i]   <- char_of_int (c lsr 4 + 48);
    hex.[2*i+1] <- char_of_int (c land 0x0F + 48)
  done;
  hex

let write_object hash contents =
  let path = ".minigit/objects/" ^ hash in
  let oc = open_out_bin path in
  output_string oc contents;
  close_out oc

let read_file filename =
  let ic = open_in_bin filename in
  let n = in_channel_length ic in
  let s = really_input_string ic n in
  close_in ic;
  s

let add filename =
  if not (Sys.file_exists filename) then
    (prerr_endline ("minigit: " ^ filename ^ ": No such file or directory"); exit 1);
  let contents = read_file filename in
  let hash = hash_contents contents in
  write_object hash contents;
  let ic = open_in ".minigit/index" in
  let entries = ref [] in
  (try
     while true do
       let line = input_line ic in
       let space = String.index line ' ' in
       let name = String.sub line (space + 1) (String.length line - space - 1) in
       if name <> filename then
         entries := line :: !entries
     done
   with End_of_file -> ());
  close_in ic;
  let oc = open_out ".min/git/index" in
  List.iter (fun line -> output_string oc (line ^ "\n")) !entries;
  output_string oc (hash ^ " " ^ filename ^ "\n");
  close_out oc

let cmdline () =
  let args = Array.to_list (Array.sub Sys.argv 1 (Array.length Sys.argv - 1)) in
  match args with
  | ["init"] -> init ()
  | ["add"; file] -> add file
  | _ ->
     prerr_endline "usage: minigit init | add <file>";
     exit 1

let () = cmdline ()
